      if (lookahead == '"') ADVANCE(1);
      END_STATE();
    case 24:
      ACCEPT_TOKEN(aux_sym_one_line_string_token1);
      if (lookahead == '\\') ADVANCE(5);
      if (lookahead != 0 &&
          lookahead != '"') ADVANCE(24);
      END_STATE();
    case 25:
